<?php
    $siboHelpRole = auth()->check() ? strtolower((string) (auth()->user()->role ?? 'anggota')) : 'publik';
?>

<div x-data="siboStepByStepGuide(<?php echo \Illuminate\Support\Js::from($siboHelpRole)->toHtml() ?>)" x-cloak x-init="boot()">
    <button type="button" class="sibo-help-fab" title="Mulai panduan halaman ini" @click="startCurrentPageGuide()">?</button>

    <template x-if="tourOpen">
        <div>
            <div class="sibo-tour-dim"></div>
            <div class="sibo-tour-highlight" :style="highlightStyle"></div>
            <div class="sibo-tour-popover" :style="popoverStyle">
                <div class="sibo-tour-popover-head">
                    <div>
                        <p x-text="activeGuide?.eyebrow || 'Panduan SIBO'"></p>
                        <h3 x-text="currentStep?.title || 'Langkah'"></h3>
                    </div>
                    <button type="button" @click="closeTour()">×</button>
                </div>

                <div class="sibo-tour-progress"><div :style="`width:${progressPercent}%`"></div></div>
                <p class="sibo-tour-step-text" x-text="currentStep?.body"></p>
                <template x-if="currentStep?.note"><div class="sibo-tour-note" x-text="currentStep.note"></div></template>

                <div class="sibo-tour-footer">
                    <span><strong x-text="stepIndex + 1"></strong>/<span x-text="activeGuide?.steps.length || 1"></span></span>
                    <div>
                        <button type="button" class="secondary" @click="prevStep()" :disabled="stepIndex === 0">Back</button>
                        <button type="button" class="primary" @click="nextStep()" x-text="isLastStep ? 'Selesai' : 'Next'"></button>
                    </div>
                </div>
            </div>
        </div>
    </template>
</div>

<style>
