function siboStepByStepGuide(authRole){return{tourOpen:false,activeGuideKey:null,stepIndex:0,popoverStyle:'left:24px;top:120px;',highlightStyle:'display:none;',authRole:(authRole||'publik').toLowerCase(),guides:[],boot(){this.guides=this.makeGuides()},normalizeRole(role){role=String(role||'').toLowerCase();if(role.includes('admin'))return'admin';if(role.includes('pac'))return'pac';if(role.includes('anggota'))return'anggota';return'publik'},get activeGuide(){return this.guides.find(g=>g.key===this.activeGuideKey)||this.guideForCurrentPage()},get currentStep(){return this.activeGuide?.steps[this.stepIndex]||null},get progressPercent(){const total=this.activeGuide?.steps.length||1;return Math.round(((this.stepIndex+1)/total)*100)},get isLastStep(){return this.stepIndex>=((this.activeGuide?.steps.length||1)-1)},startCurrentPageGuide(){const guide=this.guideForCurrentPage();this.activeGuideKey=guide?.key;this.stepIndex=0;this.tourOpen=true;this.$nextTick(()=>this.positionCurrentStep(true));window.addEventListener('resize',this._resizeHandler=()=>this.positionCurrentStep());window.addEventListener('scroll',this._scrollHandler=()=>this.positionCurrentStep(),true)},closeTour(){this.tourOpen=false;this.highlightStyle='display:none;';if(this._resizeHandler)window.removeEventListener('resize',this._resizeHandler);if(this._scrollHandler)window.removeEventListener('scroll',this._scrollHandler,true)},nextStep(){if(this.isLastStep)return this.closeTour();this.stepIndex++;this.$nextTick(()=>this.positionCurrentStep(true))},prevStep(){if(this.stepIndex===0)return;this.stepIndex--;this.$nextTick(()=>this.positionCurrentStep(true))},isVisible(el){if(!el)return false;const s=getComputedStyle(el);const r=el.getBoundingClientRect();return s.display!=='none'&&s.visibility!=='hidden'&&r.width>8&&r.height>8&&!el.closest('.sibo-tour-popover')&&!el.closest('.sibo-tour-dim')},firstVisible(selector){if(!selector)return null;return Array.from(document.querySelectorAll(selector)).find(el=>this.isVisible(el))||null},findByText(text,tags='a,button,label,h1,h2,h3,span,div'){if(!text)return null;const q=String(text).toLowerCase();return Array.from(document.querySelectorAll(tags)).find(el=>this.isVisible(el)&&(el.innerText||el.textContent||'').trim().toLowerCase().includes(q))||null},resolveTarget(step){return this.firstVisible(step.selector)||this.findByText(step.text,step.tags)||this.firstVisible(step.fallback)||null},positionCurrentStep(scrollToTarget=false){const step=this.currentStep;if(!step)return;const el=this.resolveTarget(step);const vw=window.innerWidth;const vh=window.innerHeight;const popW=Math.min(410,vw-32);const popH=270;const navbarSafeTop=96;if(el){if(scrollToTarget)el.scrollIntoView({behavior:'smooth',block:'center',inline:'center'});setTimeout(()=>{const r=el.getBoundingClientRect();const pad=10;this.highlightStyle=`left:${Math.max(8,r.left-pad)}px;top:${Math.max(8,r.top-pad)}px;width:${Math.max(44,r.width+pad*2)}px;height:${Math.max(34,r.height+pad*2)}px;display:block;`;let left=r.left+(r.width/2)-(popW/2);left=Math.max(16,Math.min(left,vw-popW-16));let below=r.bottom+18;let above=r.top-popH-18;let top=below;if(below+popH>vh-16&&above>navbarSafeTop)top=above;if(top<navbarSafeTop)top=navbarSafeTop;if(top+popH>vh-16)top=Math.max(navbarSafeTop,vh-popH-16);this.popoverStyle=`left:${left}px;top:${top}px;`;},scrollToTarget?260:0)}else{this.highlightStyle='display:none;';this.popoverStyle=`left:${Math.max(16,(vw-popW)/2)}px;top:${Math.max(120,(vh-popH)/2)}px;`}},guideForCurrentPage(){const path=window.location.pathname.toLowerCase();const role=this.normalizeRole(this.authRole);const isCreate=path.includes('/create')||path.includes('/edit');const checks=[['admin/anggota',isCreate?'admin-anggota-form':'admin-anggota'],['admin/kategori',isCreate?'admin-kategori-form':'admin-kategori'],['admin/kegiatan',isCreate?'admin-kegiatan-form':'admin-kegiatan'],['admin/pendaftaran',isCreate?'admin-pendaftaran-form':'admin-pendaftaran'],['admin/absensi','admin-ab